<span class="line"><span style="color:#F07178;">          text</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Learn Vue.js 3</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
